  /* 카테고리 아이콘 그리드 */
  .category-grid {
    display: grid;
    grid-template-columns: repeat(6, 1fr);
    gap: 16px;
  }
  .category-item {
    background: var(--white);
    border-radius: var(--radius-lg);
    padding: 24px 16px;
    text-align: center;
    cursor: pointer;
    transition: var(--transition);
    border: 1px solid var(--gray-200);
  }
  .category-item:hover {
    border-color: var(--primary);
    background: var(--primary-light);
    transform: translateY(-2px);
  }
  .category-icon {
    width: 56px;
    height: 56px;
    border-radius: var(--radius-lg);
    display: flex;
    align-items: center;
    justify-content: center;
    margin: 0 auto 12px;
    font-size: 28px;
  }
  .category-name {
    font-size: 14px;
    font-weight: 600;
    color: var(--gray-800);
  }

  /* 상품 그리드 */
  .product-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 24px;
  }
  @media (max-width: 992px) {
    .product-grid { grid-template-columns: repeat(3, 1fr); }
    .category-grid { grid-template-columns: repeat(3, 1fr); }
  }
  @media (max-width: 768px) {
    .product-grid { grid-template-columns: repeat(2, 1fr); }
    .category-grid { grid-template-columns: repeat(3, 1fr); }
  }

  /* 상품 정보 */
  .product-info {
    padding: 16px;
  }
  .product-seller {
    font-size: 12px;
    color: var(--gray-600);
    margin-bottom: 6px;
  }
  .product-name {
    font-size: 14px;
    font-weight: 500;
    color: var(--gray-900);
    margin-bottom: 8px;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
    line-height: 1.4;
    min-height: 40px;
  }
  .product-price-wrap {
    display: flex;
    align-items: baseline;
    gap: 6px;
    margin-bottom: 8px;
  }
  .product-discount {
    font-size: 16px;
    font-weight: 700;
    color: var(--secondary);
  }
  .product-price {
    font-size: 16px;
    font-weight: 700;
    color: var(--gray-900);
  }
  .product-original-price {
    font-size: 12px;
    color: var(--gray-500);
    text-decoration: line-through;
  }
  .product-meta {
    display: flex;
    align-items: center;
    gap: 8px;
    font-size: 12px;
    color: var(--gray-600);
  }
  .product-rating {
    display: flex;
    align-items: center;
    gap: 2px;
  }
  .star-icon {
    color: #ffc107;
    font-size: 12px;
  }

  /* 장바구니 슬라이드 */
  .cart-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0,0,0,0.5);
    z-index: 1040;
    opacity: 0;
    animation: fadeIn 0.2s forwards;
  }
  @keyframes fadeIn {
    to { opacity: 1; }
  }
  .cart-panel {
    position: fixed;
    top: 0;
    right: 0;
    width: 420px;
    height: 100%;
    background: var(--white);
    z-index: 1050;
    display: flex;
    flex-direction: column;
    box-shadow: var(--shadow-xl);
    transform: translateX(100%);
    animation: slideIn 0.3s forwards;
  }
  @keyframes slideIn {
    to { transform: translateX(0); }
  }
  .cart-header {
    padding: 20px 24px;
    border-bottom: 1px solid var(--gray-200);
    display: flex;
    justify-content: space-between;
    align-items: center;
  }
  .cart-header h3 {
    font-size: 18px;
    font-weight: 700;
  }
  .cart-body {
    flex: 1;
    overflow-y: auto;
    padding: 16px 24px;
  }
  .cart-item {
    display: flex;
    gap: 16px;
    padding: 16px 0;
    border-bottom: 1px solid var(--gray-200);
  }
  .cart-item-image {
    width: 80px;
    height: 80px;
    border-radius: var(--radius-md);
    overflow: hidden;
    flex-shrink: 0;
  }
  .cart-item-image img {
    width: 100%;
    height: 100%;
    object-fit: cover;
  }
  .cart-footer {
    padding: 20px 24px;
    border-top: 1px solid var(--gray-200);
    background: var(--gray-100);
  }

  /* 상품 상세 */
  .detail-images {
    position: sticky;
    top: 100px;
  }
  .detail-main-image {
    width: 100%;
    aspect-ratio: 1;
    border-radius: var(--radius-lg);
    overflow: hidden;
    margin-bottom: 12px;
    background: var(--gray-100);
  }
  .detail-main-image img {
    width: 100%;
    height: 100%;
    object-fit: cover;
  }
  .detail-thumbnails {
    display: flex;
    gap: 8px;
  }
  .detail-thumbnail {
    width: 72px;
    height: 72px;
    border-radius: var(--radius-md);
    overflow: hidden;
    cursor: pointer;
    border: 2px solid transparent;
    transition: var(--transition);
    opacity: 0.6;
  }
  .detail-thumbnail:hover, .detail-thumbnail.active {
    border-color: var(--primary);
    opacity: 1;
  }
  .detail-thumbnail img {
    width: 100%;
    height: 100%;
    object-fit: cover;
  }

  .detail-info {
    padding-left: 48px;
  }
  .detail-breadcrumb {
    font-size: 13px;
    color: var(--gray-600);
    margin-bottom: 16px;
  }
  .detail-breadcrumb a {
