  }
  .detail-title {
    font-size: 24px;
    font-weight: 700;
    color: var(--gray-900);
    margin-bottom: 16px;
    line-height: 1.4;
  }
  .detail-rating {
    display: flex;
    align-items: center;
    gap: 8px;
    margin-bottom: 24px;
    padding-bottom: 24px;
    border-bottom: 1px solid var(--gray-200);
  }
  .detail-price-section {
    margin-bottom: 24px;
    padding-bottom: 24px;
    border-bottom: 1px solid var(--gray-200);
  }
  .detail-original-price {
    font-size: 14px;
    color: var(--gray-500);
    text-decoration: line-through;
    margin-bottom: 4px;
  }
  .detail-price-row {
    display: flex;
    align-items: baseline;
    gap: 8px;
  }
  .detail-discount {
    font-size: 28px;
    font-weight: 900;
    color: var(--secondary);
  }
  .detail-price {
    font-size: 28px;
    font-weight: 900;
    color: var(--gray-900);
  }
  .detail-info-list {
    margin-bottom: 24px;
    padding-bottom: 24px;
    border-bottom: 1px solid var(--gray-200);
  }
  .detail-info-item {
    display: flex;
    padding: 12px 0;
    font-size: 14px;
  }
  .detail-info-label {
    width: 100px;
    color: var(--gray-600);
  }
  .detail-info-value {
    color: var(--gray-900);
  }

  .quantity-control {
    display: flex;
    align-items: center;
    border: 1px solid var(--gray-300);
    border-radius: var(--radius-md);
    overflow: hidden;
  }
  .quantity-btn {
