  }
  .total-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
  }
  .total-label {
    font-size: 14px;
    color: var(--gray-700);
  }
  .total-price {
    font-size: 24px;
    font-weight: 900;
    color: var(--primary);
  }

  .action-buttons {
    display: flex;
    gap: 12px;
  }
  .btn-cart {
    flex: 1;
    padding: 16px;
    border: 2px solid var(--gray-300);
    background: var(--white);
    border-radius: var(--radius-lg);
    font-size: 16px;
    font-weight: 700;
    cursor: pointer;
    transition: var(--transition);
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
  }
  .btn-cart:hover {
    border-color: var(--primary);
    color: var(--primary);
  }
  .btn-buy {
    flex: 2;
    padding: 16px;
    border: none;
    background: var(--primary);
    color: white;
    border-radius: var(--radius-lg);
    font-size: 16px;
    font-weight: 700;
    cursor: pointer;
    transition: var(--transition);
  }
  .btn-buy:hover {
    background: var(--primary-dark);
  }

  /* 탭 네비게이션 */
  .tab-nav {
    display: flex;
    border-bottom: 1px solid var(--gray-300);
    margin-top: 48px;
    position: sticky;
    top: 70px;
    background: var(--white);
    z-index: 100;
  }
  .tab-item {
    padding: 16px 32px;
    font-size: 15px;
    font-weight: 600;
    color: var(--gray-600);
    background: none;
    border: none;
    cursor: pointer;
    position: relative;
    transition: var(--transition);
  }
  .tab-item:hover {
    color: var(--gray-900);
  }
  .tab-item.active {
    color: var(--primary);
  }
  .tab-item.active::after {
    content: '';
    position: absolute;
    bottom: -1px;
    left: 0;
    right: 0;
    height: 2px;
    background: var(--primary);
  }

  /* 리뷰 */
  .review-summary {
    display: flex;
    align-items: center;
    gap: 32px;
    padding: 32px;
    background: var(--gray-100);
    border-radius: var(--radius-lg);
    margin-bottom: 24px;
  }
  .review-score {
    text-align: center;
  }
  .review-score-number {
    font-size: 48px;
    font-weight: 900;
    color: var(--gray-900);
    line-height: 1;
  }
  .review-score-stars {
    color: #ffc107;
    font-size: 20px;
    margin: 8px 0;
  }
  .review-score-count {
    font-size: 14px;
    color: var(--gray-600);
  }
  .review-bars {
    flex: 1;
  }
  .review-bar-item {
    display: flex;
    align-items: center;
    gap: 8px;
    margin-bottom: 4px;
  }
  .review-bar-label {
    width: 50px;
    font-size: 13px;
    color: var(--gray-600);
  }
  .review-bar-track {
