    background: var(--primary);
    border-radius: 4px;
  }
  .review-item {
    padding: 24px 0;
    border-bottom: 1px solid var(--gray-200);
  }
  .review-header {
    display: flex;
    justify-content: space-between;
    margin-bottom: 12px;
  }
  .review-user {
    display: flex;
    align-items: center;
    gap: 12px;
  }
  .review-avatar {
    width: 40px;
    height: 40px;
    border-radius: 50%;
    background: var(--gray-200);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 18px;
  }
  .review-user-info {
    font-size: 14px;
  }
  .review-user-name {
    font-weight: 600;
    color: var(--gray-900);
  }
  .review-date {
