  }
  .review-photo img {
    width: 100%;
    height: 100%;
    object-fit: cover;
  }

  /* 푸터 */
  .footer {
    background: var(--gray-900);
    color: var(--gray-400);
    padding: 64px 0 32px;
    margin-top: 80px;
  }
  .footer-top {
    display: grid;
    grid-template-columns: 2fr 1fr 1fr 1fr;
    gap: 48px;
    padding-bottom: 48px;
    border-bottom: 1px solid var(--gray-800);
  }
  .footer-logo {
    font-size: 28px;
    font-weight: 900;
    color: var(--primary);
    margin-bottom: 16px;
  }
  .footer-desc {
    font-size: 14px;
    line-height: 1.7;
    margin-bottom: 24px;
  }
  .footer-social {
    display: flex;
    gap: 12px;
  }
  .footer-social a {
    width: 40px;
    height: 40px;
    border-radius: 50%;
    background: var(--gray-800);
