  .dropdown-item-custom {
    display: block;
    width: 100%;
    padding: 12px 16px;
    border: none;
    background: none;
    text-align: left;
    font-size: 14px;
    color: var(--gray-800);
    cursor: pointer;
    transition: var(--transition);
