    height: 1px;
    background: var(--gray-200);
    margin: 4px 0;
  }
`;

// 상품 데이터 (제거됨 - dynamicProducts state 사용)


const categories = [
  { id: 'all', name: '전체', icon: '🏠', color: '#35c5f0' },
  { id: 'furniture', name: '가구', icon: '🪑', color: '#ff6b6b' },
  { id: 'lighting', name: '조명', icon: '💡', color: '#ffd93d' },
  { id: 'fabric', name: '패브릭', icon: '🛋️', color: '#6bcb77' },
  { id: 'deco', name: '소품', icon: '🏺', color: '#a855f7' },
  { id: 'kitchen', name: '주방', icon: '🍳', color: '#4d96ff' },
];

const banners = [
  { id: 1, title: '2026 신년맞이\n인테리어 대전', subtitle: '전 상품 최대 70% 할인', cta: '할인 상품 보러가기', bg: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)', textColor: 'white' },
  { id: 2, title: '프리미엄 가구\n기획전', subtitle: '지금 구매하면 무료 배송', cta: '기획전 바로가기', bg: 'linear-gradient(135deg, #f093fb 0%, #f5576c 100%)', textColor: 'white' },
  { id: 3, title: '따뜻한 겨울 준비\n패브릭 컬렉션', subtitle: '이불, 러그, 커튼 총집합', cta: '컬렉션 보기', bg: 'linear-gradient(135deg, #4facfe 0%, #00f2fe 100%)', textColor: 'white' },
];

export default function ClientShop() {
  const [currentPage, setCurrentPage] = useState('home');
  const [selectedCategory, setSelectedCategory] = useState('전체');
  const [sortBy, setSortBy] = useState('popular');
  const [cart, setCart] = useState([]);
  const [selectedProduct, setSelectedProduct] = useState(null);
  const [showCart, setShowCart] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [currentBanner, setCurrentBanner] = useState(0);
  const [quantity, setQuantity] = useState(1);
  const [showCheckout, setShowCheckout] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [wishlist, setWishlist] = useState([]);
  const [showDropdown, setShowDropdown] = useState(false);
  const [selectedPayment, setSelectedPayment] = useState('card');
  const [isOpenPostcode, setIsOpenPostcode] = useState(false);
  const [recentOrder, setRecentOrder] = useState(null);
  const [myOrders, setMyOrders] = useState([]);
  const [dynamicProducts, setDynamicProducts] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [selectedOrderDetail, setSelectedOrderDetail] = useState(null);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [isDetailLoading, setIsDetailLoading] = useState(false);

  // 배송 정보 상태 추가
  const [shippingInfo, setShippingInfo] = useState({
    receiverName: '',
    receiverPhone: '',
    zipCode: '',
    address1: '',
    address2: '',
    shippingMessage: ''
  });

  const [loginForm, setLoginForm] = useState({
    email: '',
    password: ''
  });

  // 초기 로딩: 상품 데이터 및 로그인 상태 체크
  useEffect(() => {
    const init = async () => {
      setIsLoading(true);
      try {
        // 상품 데이터 페치
        const productRes = await ProductService.getProducts(0, 50);
        if (productRes && productRes.content) {
          // 백엔드 DTO -> 프론트엔드 형식 매핑
          const mappedProducts = productRes.content.map(p => ({
            id: p.seq,
            name: p.productName,
            price: p.salePrice || p.price,
            originalPrice: p.price,
            category: p.categoryName || '기타',
            image: p.thumbnailUrl || 'https://via.placeholder.com/400',
            rating: p.ratingAvg ? parseFloat(p.ratingAvg) : 0,
            reviews: p.reviewCount || 0,
            seller: p.marketName || '일반판매자',
            badge: p.saleCount > 10 ? 'BEST' : '',
            description: p.productName, // 상세 설명은 목록에서 안 넘어올 수 있음
            freeShipping: true
          }));
          setDynamicProducts(mappedProducts);
        }

        // 로그인 상태 체크
        const token = localStorage.getItem('accessToken');
        if (token) {
          const isOk = await OrderService.checkLogin();
          setIsLoggedIn(isOk);
        }
      } catch (err) {
        console.error("Initialization failed", err);
      } finally {
        setIsLoading(false);
      }
    };
    init();
  }, []);

  const handleShowOrderDetail = async (orderSeq) => {
    setIsDetailLoading(true);
    setShowDetailModal(true);
    try {
      const detail = await OrderService.getOrderDetail(orderSeq);
      setSelectedOrderDetail(detail);
    } catch (err) {
      console.error("Failed to load order detail", err);
      alert('주문 상세 정보를 불러오는데 실패했습니다.');
      setShowDetailModal(false);
    } finally {
      setIsDetailLoading(false);
    }
  };

  // 배너 자동 슬라이드
  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentBanner((prev) => (prev + 1) % banners.length);
    }, 5000);
    return () => clearInterval(timer);
  }, []);

  // 데이터 로딩 (mypage)
  useEffect(() => {
    if (currentPage === 'mypage' && isLoggedIn) {
      OrderService.getMyOrders().then(res => {
        if (res && res.content) {
          setMyOrders(res.content);
        }
      }).catch(err => console.error("Failed to load orders", err));
    }
  }, [currentPage, isLoggedIn]);

  // 페이지 이동 함수
  const goToHome = () => {
    setCurrentPage('home');
    setSelectedProduct(null);
  };

  // 필터링 및 정렬
  const filteredProducts = dynamicProducts
    .filter(p => selectedCategory === '전체' || p.category === selectedCategory)
    .filter(p => p.name.toLowerCase().includes(searchTerm.toLowerCase()))
    .sort((a, b) => {
      if (sortBy === 'popular') return b.reviews - a.reviews;
      if (sortBy === 'rating') return b.rating - a.rating;
      if (sortBy === 'priceLow') return a.price - b.price;
      if (sortBy === 'priceHigh') return b.price - a.price;
      if (sortBy === 'newest') return b.id - a.id;
      return 0;
    });

  // 장바구니 함수
  const addToCart = (product, qty = 1) => {
    const existing = cart.find(item => item.id === product.id);
    if (existing) {
      setCart(cart.map(item =>
        item.id === product.id ? { ...item, quantity: item.quantity + qty } : item
      ));
    } else {
      setCart([...cart, { ...product, quantity: qty }]);
    }
  };

  const updateCartQuantity = (productId, newQty) => {
    if (newQty < 1) {
      setCart(cart.filter(item => item.id !== productId));
    } else {
      setCart(cart.map(item =>
        item.id === productId ? { ...item, quantity: newQty } : item
      ));
    }
  };

  const removeFromCart = (productId) => {
    setCart(cart.filter(item => item.id !== productId));
  };

  const toggleWishlist = (productId) => {
    if (wishlist.includes(productId)) {
      setWishlist(wishlist.filter(id => id !== productId));
    } else {
      setWishlist([...wishlist, productId]);
    }
  };

  const cartTotal = cart.reduce((sum, item) => sum + item.price * item.quantity, 0);
  const cartCount = cart.reduce((sum, item) => sum + item.quantity, 0);
  const getDiscount = (original, current) => Math.round((1 - current / original) * 100);

  // 주문 관련 함수
  const handleOrderClick = async () => {
    if (cart.length === 0) {
      alert('장바구니가 비어 있습니다.');
      return;
    }
    try {
      const token = localStorage.getItem('accessToken');
      if (!token) {
        alert('주문을 위해 로그인이 필요합니다.');
        setShowLoginModal(true);
        return;
      }
      const isOk = await OrderService.checkLogin();
      if (isOk) {
        setIsLoggedIn(true);
        setShowCheckout(true);
        setShowCart(false);
      } else {
        localStorage.removeItem('accessToken');
        setIsLoggedIn(false);
        alert('세션이 만료되었습니다. 다시 로그인해주세요.');
        setShowLoginModal(true);
      }
    } catch (error) {
      alert('주문을 위해 로그인이 필요합니다.');
      setShowLoginModal(true);
    }
  };

  const handleBuyNow = async (product, qty) => {
    try {
      const token = localStorage.getItem('accessToken');
      if (!token) {
        alert('바로 구매를 위해 로그인이 필요합니다.');
        setShowLoginModal(true);
        return;
      }
      const isOk = await OrderService.checkLogin();
      if (isOk) {
        setIsLoggedIn(true);
        // 기존 장바구니 데이터를 덮어쓰거나, 선택한 상품만으로 주문을 구성하도록 처리
        setCart([{ ...product, quantity: qty }]);
        setShowCheckout(true);
        setShowCart(false);
      } else {
        localStorage.removeItem('accessToken');
        setIsLoggedIn(false);
        alert('세션이 만료되었습니다. 다시 로그인해주세요.');
        setShowLoginModal(true);
      }
    } catch (error) {
      alert('바로 구매를 위해 로그인이 필요합니다.');
      setShowLoginModal(true);
    }
  };

  const handleCompletePostcode = (data) => {
    let fullAddress = data.address;
    let extraAddress = '';

    if (data.addressType === 'R') {
      if (data.bname !== '') extraAddress += data.bname;
      if (data.buildingName !== '') extraAddress += extraAddress !== '' ? `, ${data.buildingName}` : data.buildingName;
      fullAddress += extraAddress !== '' ? ` (${extraAddress})` : '';
    }

    setShippingInfo({
      ...shippingInfo,
      zipCode: data.zonecode,
      address1: fullAddress,
    });
    setIsOpenPostcode(false);
  };

  const handleLogin = async () => {
    try {
      await AuthService.login(loginForm.email, loginForm.password);
      setIsLoggedIn(true);
      setShowLoginModal(false);
      alert('로그인되었습니다.');
    } catch (error) {
      alert('로그인에 실패했습니다. 이메일과 비밀번호를 확인해주세요.');
    }
  };

  const handlePaymentSubmit = async (e) => {
    if (e) e.preventDefault();

    // 필수 입력값 검증 (이름, 연락처, 주소)
    if (!shippingInfo.receiverName.trim()) {
      alert('수령인 이름을 입력해주세요.');
      return;
    }
    if (!shippingInfo.receiverPhone.trim()) {
      alert('연락처를 입력해주세요.');
      return;
    }
    if (!shippingInfo.zipCode || !shippingInfo.address1.trim() || !shippingInfo.address2.trim()) {
      alert('주소(우편번호, 도로명/지번, 상세주소)를 모두 입력해주세요.');
      return;
    }

    const orderData = {
      items: cart.map(item => ({
        productSeq: item.id,
        qty: item.quantity
      })),
      ...shippingInfo
    };

    try {
      const response = await OrderService.createOrder(orderData);

      // 알림 노출 후 상태 변경을 위해 순차 처리 (alert가 닫히기 전까지는 아래 코드가 실행되지 않음)
      alert('주문이 성공적으로 완료되었습니다!');

      setRecentOrder({
        ...response,
        items: cart,
        shipping: shippingInfo,
        payment: selectedPayment
      });
      setCart([]);
      setShowCheckout(false);
      setSelectedProduct(null);
      window.scrollTo(0, 0); // 스크롤을 최상단으로 이동
      setCurrentPage('orderComplete');
    } catch (error) {
      if (error.message === 'UNAUTHORIZED') {
        alert('세션이 만료되었습니다. 다시 로그인해주세요.');
        setShowLoginModal(true);
      } else {
        alert(error.message || '주문 처리 중 오류가 발생했습니다.');
      }
    }
  };

  // 상품 카드 컴포넌트
  const ProductCard = ({ product }) => (
    <div className="product-card" onClick={() => { setSelectedProduct(product); setQuantity(1); }}>
      <div className="product-image">
        <img src={product.image} alt={product.name} />
        {product.badge && (
          <span className={`badge-${product.badge.toLowerCase()}`} style={{ position: 'absolute', top: '12px', left: '12px' }}>
            {product.badge}
          </span>
        )}
        <button
          className={`wishlist-btn ${wishlist.includes(product.id) ? 'active' : ''}`}
          style={{ position: 'absolute', top: '12px', right: '12px' }}
          onClick={(e) => { e.stopPropagation(); toggleWishlist(product.id); }}
        >
          {wishlist.includes(product.id) ? '❤️' : '🤍'}
        </button>
        {product.freeShipping && (
          <span className="badge-free-shipping" style={{ position: 'absolute', bottom: '12px', left: '12px' }}>
            무료배송
          </span>
        )}
      </div>
      <div className="product-info">
        <p className="product-seller">{product.seller}</p>
        <h3 className="product-name">{product.name}</h3>
        <div className="product-price-wrap">
          <span className="product-discount">{getDiscount(product.originalPrice, product.price)}%</span>
          <span className="product-price">₩{product.price.toLocaleString()}</span>
        </div>
        <div className="product-meta">
          <div className="product-rating">
            <span className="star-icon">★</span>
            <span>{product.rating}</span>
          </div>
          <span>리뷰 {product.reviews.toLocaleString()}</span>
        </div>
      </div>
    </div>
  );

  // 로딩 화면
  if (isLoading) {
    return (
      <div style={{
        height: '100vh',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        background: '#ffffff'
      }}>
        <div style={{
          width: '40px',
          height: '40px',
          border: '3px solid #f3f3f3',
          borderTop: '3px solid #35c5f0',
          borderRadius: '50%',
          animation: 'spin 1s linear infinite'
        }} />
        <style>{`
          @keyframes spin {
            0% { transform: rotate(0deg); }
            100% { transform: rotate(360deg); }
          }
        `}</style>
        <p style={{ marginTop: '16px', color: '#828c94', fontWeight: '500' }}>상품 정보를 불러오는 중입니다...</p>
      </div>
    );
  }

  return (
    <>
      <style>{styles}</style>

      {/* 헤더 */}
      <header className="header-main">
        {/* 상단 바 */}
        <div className="header-top">
          <div className="container d-flex justify-content-end gap-4">
            <a href="#!" style={{ color: 'inherit', textDecoration: 'none' }}>고객센터</a>
            <a href="#!" style={{ color: 'inherit', textDecoration: 'none' }}>판매자 센터</a>
          </div>
        </div>

        {/* 메인 헤더 */}
        <div className="container">
          <div className="d-flex align-items-center justify-content-between py-3 gap-4">
            <a href="#!" className="logo" onClick={(e) => { e.preventDefault(); setCurrentPage('home'); setSelectedProduct(null); }}>
              마이샵
            </a>

            <div className="search-box">
              <input
                type="text"
                placeholder="검색어를 입력해주세요"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && setCurrentPage('products')}
              />
              <button onClick={() => setCurrentPage('products')}>
                🔍
              </button>
            </div>

            <div className="d-flex align-items-center gap-2">
              <button className="header-icon-btn" onClick={() => setShowCart(true)}>
                🛒
                {cartCount > 0 && <span className="header-badge">{cartCount}</span>}
              </button>

              {isLoggedIn ? (
                <div className="user-dropdown">
                  <button className="user-btn" onClick={() => setShowDropdown(!showDropdown)}>
                    <span className="user-avatar">👤</span>
                    <span>김고객</span>
                  </button>
                  {showDropdown && (
                    <div className="dropdown-menu-custom">
                      <button className="dropdown-item-custom" onClick={() => { setCurrentPage('mypage'); setShowDropdown(false); setSelectedProduct(null); }}>마이페이지 (주문조회)</button>
                      <button className="dropdown-item-custom">찜한 상품</button>
                      <div className="dropdown-divider" />
                      <button className="dropdown-item-custom" onClick={() => {
                        AuthService.logout();
                        setIsLoggedIn(false);
                        setShowDropdown(false);
                      }}>
                        로그아웃
                      </button>
                    </div>
                  )}
                </div>
              ) : (
                <button className="login-btn" onClick={() => setShowLoginModal(true)}>
                  로그인
                </button>
              )}
            </div>
          </div>

          {/* 카테고리 네비게이션 */}
          <nav className="category-nav">
            {['전체', '가구', '조명', '패브릭', '소품', '주방', '베스트', '신상품', '이벤트'].map(cat => (
              <a
                key={cat}
                href="#!"
                className={`category-link ${selectedCategory === cat ? 'active' : ''}`}
                onClick={(e) => { e.preventDefault(); setSelectedCategory(cat === '베스트' || cat === '신상품' || cat === '이벤트' ? '전체' : cat); setCurrentPage('products'); }}
              >
                {cat}
              </a>
            ))}
          </nav>
        </div>
      </header>

      {/* 메인 콘텐츠 */}
      <main>
        {/* 홈 페이지 */}
        {currentPage === 'home' && !selectedProduct && (
          <div className="container py-4">
            {/* 메인 배너 */}
            <div className="main-banner">
              <div
                className="banner-slide"
                style={{ background: banners[currentBanner].bg, color: banners[currentBanner].textColor }}
              >
                <div className="banner-content">
                  <h2 style={{ whiteSpace: 'pre-line' }}>{banners[currentBanner].title}</h2>
                  <p>{banners[currentBanner].subtitle}</p>
                  <button className="btn-primary-custom" style={{ background: 'rgba(255,255,255,0.2)', backdropFilter: 'blur(4px)' }}>
                    {banners[currentBanner].cta} →
                  </button>
                </div>
              </div>
              <button className="banner-arrow prev" onClick={() => setCurrentBanner((currentBanner - 1 + banners.length) % banners.length)}>‹</button>
              <button className="banner-arrow next" onClick={() => setCurrentBanner((currentBanner + 1) % banners.length)}>›</button>
              <div className="banner-dots">
                {banners.map((_, i) => (
                  <button key={i} className={`banner-dot ${i === currentBanner ? 'active' : ''}`} onClick={() => setCurrentBanner(i)} />
                ))}
              </div>
            </div>

            {/* 카테고리 */}
            <section className="section">
              <div className="section-header">
                <h2 className="section-title">카테고리</h2>
              </div>
              <div className="category-grid">
                {categories.map(cat => (
                  <div
                    key={cat.id}
                    className="category-item"
                    onClick={() => { setSelectedCategory(cat.name); setCurrentPage('products'); }}
                  >
                    <div className="category-icon" style={{ background: `${cat.color}15` }}>
                      {cat.icon}
                    </div>
                    <div className="category-name">{cat.name}</div>
                  </div>
                ))}
              </div>
            </section>

            {/* 베스트 상품 */}
            <section className="section">
              <div className="section-header">
                <h2 className="section-title">
                  <span style={{ color: '#ff6b6b' }}>🔥</span> 베스트 상품
                </h2>
                <a href="#!" className="section-more" onClick={(e) => { e.preventDefault(); setCurrentPage('products'); }}>
                  더보기 <span>›</span>
                </a>
              </div>
              <div className="product-grid">
                {dynamicProducts.filter(p => p.badge === 'BEST').map(product => (
                  <ProductCard key={product.id} product={product} />
                ))}
              </div>
            </section>

            {/* 특가 상품 */}
            <section className="section">
              <div className="section-header">
                <h2 className="section-title">
                  <span style={{ color: '#35c5f0' }}>💰</span> 특가 세일
                </h2>
                <a href="#!" className="section-more" onClick={(e) => { e.preventDefault(); setCurrentPage('products'); }}>
                  더보기 <span>›</span>
                </a>
              </div>
              <div className="product-grid">
                {dynamicProducts.filter(p => p.badge === 'SALE').map(product => (
                  <ProductCard key={product.id} product={product} />
                ))}
              </div>
            </section>

            {/* 신상품 */}
            <section className="section">
              <div className="section-header">
                <h2 className="section-title">
                  <span style={{ color: '#a855f7' }}>✨</span> 신상품
                </h2>
                <a href="#!" className="section-more" onClick={(e) => { e.preventDefault(); setCurrentPage('products'); }}>
                  더보기 <span>›</span>
                </a>
              </div>
              <div className="product-grid">
                {dynamicProducts.filter(p => p.badge === 'NEW').map(product => (
                  <ProductCard key={product.id} product={product} />
                ))}
              </div>
            </section>
          </div>
        )}

        {/* 상품 목록 페이지 */}
        {currentPage === 'products' && !selectedProduct && (
          <div className="container py-4">
