                        onClick={() => setSelectedPayment(method.id)}
                      >
                        <div className="payment-icon">{method.icon}</div>
                        <div className="payment-name">{method.name}</div>
                      </div>
                    ))}
                  </div>
                </div>
              </div>

              {/* 결제 금액 */}
              <div className="checkout-section">
                <div className="checkout-section-header">💰 결제 금액</div>
                <div className="checkout-section-body">
                  <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '12px', fontSize: '14px' }}>
                    <span style={{ color: 'var(--gray-600)' }}>상품 금액</span>
                    <span>₩{cartTotal.toLocaleString()}</span>
                  </div>
                  <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '12px', fontSize: '14px' }}>
                    <span style={{ color: 'var(--gray-600)' }}>배송비</span>
                    <span style={{ color: cartTotal >= 50000 ? 'var(--primary)' : 'inherit' }}>{cartTotal >= 50000 ? '무료' : '₩3,000'}</span>
                  </div>
                  <div style={{ borderTop: '1px solid var(--gray-200)', paddingTop: '12px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <span style={{ fontWeight: '700' }}>총 결제금액</span>
                    <span style={{ fontSize: '24px', fontWeight: '900', color: 'var(--primary)' }}>
                      ₩{(cartTotal + (cartTotal >= 50000 ? 0 : 3000)).toLocaleString()}
                    </span>
                  </div>
                </div>
              </div>

              <button
                className="btn-buy"
                type="button"
                style={{ width: '100%', marginTop: '16px', fontSize: '18px', padding: '18px' }}
                onClick={(e) => handlePaymentSubmit(e)}
              >
                ₩{(cartTotal + (cartTotal >= 50000 ? 0 : 3000)).toLocaleString()} 결제하기
              </button>
            </div>
          </div>
        </div>
      )}

      {/* 우편번호 모달 */}
      {isOpenPostcode && (
        <div className="modal-custom">
          <div className="modal-backdrop" onClick={() => setIsOpenPostcode(false)}></div>
          <div className="modal-content-custom" style={{ padding: 0, overflow: 'hidden' }}>
            <div className="checkout-section-header" style={{ display: 'flex', justifyContent: 'space-between' }}>
              <span>우편번호 찾기</span>
              <button
                className="modal-close"
                style={{ position: 'static' }}
                onClick={() => setIsOpenPostcode(false)}
              >
                ✕
              </button>
            </div>
            <DaumPostcode
              style={{ width: '100%', height: '400px' }}
              onComplete={handleCompletePostcode}
            />
          </div>
        </div>
      )}

      {/* 로그인 모달 */}
      {showLoginModal && (
        <div className="modal-custom">
          <div className="modal-backdrop" onClick={() => setShowLoginModal(false)} />
          <div className="modal-content-custom" style={{ maxWidth: '420px' }}>
            <button className="modal-close" onClick={() => setShowLoginModal(false)}>✕</button>
            <div style={{ padding: '48px 40px' }}>
              <div style={{ textAlign: 'center', marginBottom: '32px' }}>
                <div style={{ fontSize: '48px', marginBottom: '8px' }}>🏠</div>
                <h2 style={{ fontSize: '24px', fontWeight: '700', color: 'var(--primary)' }}>마이샵</h2>
                <p style={{ color: 'var(--gray-500)', fontSize: '14px' }}>로그인하고 더 많은 혜택을 누리세요</p>
              </div>

              <div style={{ marginBottom: '16px' }}>
                <label className="form-label-custom">이메일</label>
                <input
                  className="form-control-custom"
                  type="email"
                  placeholder="이메일을 입력하세요"
                  value={loginForm.email}
                  onChange={(e) => setLoginForm({ ...loginForm, email: e.target.value })}
                />
              </div>
              <div style={{ marginBottom: '24px' }}>
                <label className="form-label-custom">비밀번호</label>
                <input
                  className="form-control-custom"
                  type="password"
                  placeholder="비밀번호를 입력하세요"
                  value={loginForm.password}
                  onChange={(e) => setLoginForm({ ...loginForm, password: e.target.value })}
                />
              </div>

              <button
                className="btn-buy"
                style={{ width: '100%', marginBottom: '16px' }}
                onClick={handleLogin}
              >
                로그인
              </button>

              <div style={{ textAlign: 'center', fontSize: '14px', color: 'var(--gray-500)', marginBottom: '24px' }}>
                계정이 없으신가요? <a href="#!" style={{ color: 'var(--primary)', fontWeight: '600' }}>회원가입</a>
              </div>

              <div style={{ position: 'relative', textAlign: 'center', marginBottom: '24px' }}>
                <span style={{ background: 'var(--white)', padding: '0 16px', color: 'var(--gray-400)', fontSize: '13px', position: 'relative', zIndex: 1 }}>또는</span>
                <div style={{ position: 'absolute', top: '50%', left: 0, right: 0, height: '1px', background: 'var(--gray-200)' }} />
              </div>

              <div style={{ display: 'flex', gap: '12px' }}>
                <button className="btn-outline-custom" style={{ flex: 1, padding: '12px' }}>🟡 카카오</button>
                <button className="btn-outline-custom" style={{ flex: 1, padding: '12px' }}>🟢 네이버</button>
                <button className="btn-outline-custom" style={{ flex: 1, padding: '12px' }}>🔵 구글</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* 주문 상세 모달 */}
      {showDetailModal && (
        <div className="modal-custom">
          <div className="modal-backdrop" onClick={() => setShowDetailModal(false)} />
          <div className="modal-content-custom" style={{ maxWidth: '720px' }}>
            <button className="modal-close" onClick={() => setShowDetailModal(false)}>✕</button>
            <div style={{ padding: '32px' }}>
              <h2 style={{ fontSize: '24px', fontWeight: '700', marginBottom: '24px' }}>주문 상세 내역</h2>

              {isDetailLoading ? (
                <div style={{ textAlign: 'center', padding: '60px 0' }}>
                  <div style={{
                    width: '40px',
                    height: '40px',
                    border: '3px solid #f3f3f3',
                    borderTop: '3px solid #35c5f0',
                    borderRadius: '50%',
                    animation: 'spin 1s linear infinite',
                    margin: '0 auto'
                  }} />
                  <p style={{ marginTop: '16px', color: 'var(--gray-600)' }}>상세 정보를 불러오는 중입니다...</p>
                </div>
              ) : selectedOrderDetail ? (
                <div style={{ maxHeight: '70vh', overflowY: 'auto', paddingRight: '8px' }}>
                  {/* 주문 요약 */}
                  <div className="checkout-section">
                    <div className="checkout-section-header">주문 정보</div>
                    <div className="checkout-section-body">
                      <div className="row g-3">
                        <div className="col-6">
                          <label style={{ color: 'var(--gray-500)', fontSize: '12px' }}>주문번호</label>
                          <p style={{ fontWeight: '700', marginBottom: 0 }}>{selectedOrderDetail.orderNo}</p>
                        </div>
                        <div className="col-6">
                          <label style={{ color: 'var(--gray-500)', fontSize: '12px' }}>주문일시</label>
                          <p style={{ fontWeight: '700', marginBottom: 0 }}>{new Date(selectedOrderDetail.orderedAt).toLocaleString()}</p>
                        </div>
                      </div>
                    </div>
                  </div>

                  {/* 배송지 정보 */}
                  <div className="checkout-section">
                    <div className="checkout-section-header">배송지 정보</div>
                    <div className="checkout-section-body">
                      <div className="mb-3">
                        <label style={{ color: 'var(--gray-500)', fontSize: '12px' }}>받는분 / 연락처</label>
                        <p style={{ fontWeight: '700', marginBottom: 0 }}>{selectedOrderDetail.receiverName} / {selectedOrderDetail.receiverPhone}</p>
                      </div>
                      <div>
                        <label style={{ color: 'var(--gray-500)', fontSize: '12px' }}>주소</label>
                        <p style={{ marginBottom: '4px' }}>({selectedOrderDetail.zipCode}) {selectedOrderDetail.address1}</p>
                        <p style={{ fontWeight: '700' }}>{selectedOrderDetail.address2}</p>
                      </div>
                      {selectedOrderDetail.shippingMessage && (
                        <div style={{ marginTop: '8px', paddingTop: '8px', borderTop: '1px solid var(--gray-200)' }}>
                          <label style={{ color: 'var(--gray-500)', fontSize: '12px' }}>배송 메세지</label>
                          <p style={{ marginBottom: 0, fontStyle: 'italic', color: 'var(--gray-600)' }}>"{selectedOrderDetail.shippingMessage}"</p>
                        </div>
                      )}
                    </div>
                  </div>

                  {/* 주문 상품 */}
                  <div className="checkout-section">
                    <div className="checkout-section-header">주문 상품 ({selectedOrderDetail.items.length})</div>
                    <div className="checkout-section-body" style={{ padding: 0 }}>
                      {selectedOrderDetail.items.map((item, idx) => (
                        <div key={idx} style={{ display: 'flex', gap: '16px', padding: '16px 20px', borderBottom: '1px solid var(--gray-200)' }}>
                          <img src={item.thumbnailUrl} alt={item.itemName} style={{ width: '64px', height: '64px', borderRadius: 'var(--radius-md)', objectFit: 'cover' }} />
                          <div style={{ flex: 1 }}>
                            <p style={{ fontSize: '14px', marginBottom: '4px', fontWeight: '500' }}>{item.itemName}</p>
                            {item.itemOption && <p style={{ fontSize: '12px', color: 'var(--gray-500)', marginBottom: '4px' }}>옵션: {item.itemOption}</p>}
                            <p style={{ fontSize: '13px', color: 'var(--gray-600)', marginBottom: '4px' }}>수량: {item.qty}개</p>
                            <p style={{ fontWeight: '700', color: 'var(--primary)' }}>₩{item.itemAmount.toLocaleString()}</p>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>

                  {/* 결제 금액 */}
                  <div className="checkout-section" style={{ backgroundColor: 'var(--primary-light)', borderColor: 'var(--primary)' }}>
                    <div className="checkout-section-body">
                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                        <span style={{ fontWeight: '700', fontSize: '16px' }}>총 결제 금액</span>
                        <span style={{ fontWeight: '900', fontSize: '24px', color: 'var(--primary)' }}>₩{selectedOrderDetail.totalPayAmount.toLocaleString()}</span>
                      </div>
                    </div>
                  </div>
                </div>
              ) : null}
            </div>
          </div>
        </div>
      )}

      {/* 푸터 */}
      <footer className="footer">
        <div className="container">
          <div className="footer-top">
            <div>
              <div className="footer-logo">마이샵</div>
              <p className="footer-desc">
                집을 더 아름답게, 삶을 더 행복하게.<br />
                당신의 공간을 완성하는 인테리어 쇼핑몰
              </p>
              <div className="footer-social">
                <a href="#!">📷</a>
                <a href="#!">📘</a>
                <a href="#!">🐦</a>
                <a href="#!">📺</a>
              </div>
            </div>
            <div>
              <h4 className="footer-title">고객센터</h4>
              <ul className="footer-links">
                <li><a href="#!">자주 묻는 질문</a></li>
                <li><a href="#!">1:1 문의</a></li>
                <li><a href="#!">배송 조회</a></li>
                <li><a href="#!">교환/반품 안내</a></li>
              </ul>
            </div>
            <div>
              <h4 className="footer-title">마이샵 소개</h4>
              <ul className="footer-links">
                <li><a href="#!">회사 소개</a></li>
                <li><a href="#!">채용 안내</a></li>
                <li><a href="#!">제휴/협력 문의</a></li>
                <li><a href="#!">판매자 입점</a></li>
              </ul>
            </div>
            <div>
              <h4 className="footer-title">고객센터</h4>
              <p className="footer-cs">1588-0000</p>
              <p className="footer-cs-time">
                평일 10:00 - 18:00<br />
                점심시간 12:30 - 13:30<br />
                주말, 공휴일 휴무
              </p>
            </div>
          </div>
          <div className="footer-bottom">
            <div className="footer-copyright">
              © 2026 마이샵 Inc. All rights reserved.
            </div>
            <div className="footer-policy">
              <a href="#!">이용약관</a>
              <a href="#!">개인정보처리방침</a>
              <a href="#!">사업자정보확인</a>
            </div>
          </div>
        </div>
      </footer>
    </>
  );
}
